import{b as t,a as n,_ as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as r,o as a,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Authentifizierung und angemeldete Geräte verwalten","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Safety/authentication-and-login-devices.md","filePath":"de-DE/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),u={name:"de-DE/Safety/authentication-and-login-devices.md"};function o(s,e,g,h,c,f){return a(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="authentifizierung-und-angemeldete-gerate-verwalten" tabindex="-1">Authentifizierung und angemeldete Geräte verwalten <a class="header-anchor" href="#authentifizierung-und-angemeldete-gerate-verwalten" aria-label="Permalink to &quot;Authentifizierung und angemeldete Geräte verwalten&quot;">​</a></h1><p>Die Authentifizierungsverwaltung zeigt Anmeldungen, aktive Sitzungen und Geräte, die im Adminbereich oder auf Benutzerseiten angemeldet sind.</p><h2 id="administrator-login" tabindex="-1">Administrator-Login <a class="header-anchor" href="#administrator-login" aria-label="Permalink to &quot;Administrator-Login&quot;">​</a></h2><p>Administratoren melden sich über die Login-Seite des Panels an, um Dateien und Einstellungen zu verwalten.</p><p><img src="'+t+'" alt="Administrator-Login" loading="lazy"></p><p>Das Administratorkonto hat weitreichende Rechte. Schütze die Zugangsdaten sorgfältig.</p><h2 id="benutzer-login" tabindex="-1">Benutzer-Login <a class="header-anchor" href="#benutzer-login" aria-label="Permalink to &quot;Benutzer-Login&quot;">​</a></h2><p>Auch für Benutzer gibt es eine Login-Seite.</p><p><img src="'+n+'" alt="Benutzer-Login" loading="lazy"></p><p>Wenn öffentliche Uploads oder eingeschränkter Zugriff genutzt werden, hilft der Benutzer-Login dabei, Aktionen Personen zuzuordnen.</p><h2 id="authentifizierungsubersicht" tabindex="-1">Authentifizierungsübersicht <a class="header-anchor" href="#authentifizierungsubersicht" aria-label="Permalink to &quot;Authentifizierungsübersicht&quot;">​</a></h2><p>Die Verwaltungsseite zeigt Sitzungen und angemeldete Geräte.</p><p><img src="'+i+'" alt="Authentifizierungsverwaltung" loading="lazy"></p><h2 id="gerate-prufen" tabindex="-1">Geräte prüfen <a class="header-anchor" href="#gerate-prufen" aria-label="Permalink to &quot;Geräte prüfen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feld</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Angemeldetes Gerät</td><td>Geräte mit aktiver Sitzung</td></tr><tr><td>IP / Standort</td><td>Hinweis zur Herkunft des Zugriffs</td></tr><tr><td>Letzter Zugriff</td><td>Zeigt, ob das Gerät noch genutzt wird</td></tr><tr><td>Widerrufen</td><td>Beendet alte oder verdächtige Sitzungen</td></tr></tbody></table><h2 id="bei-verdachtigen-sitzungen" tabindex="-1">Bei verdächtigen Sitzungen <a class="header-anchor" href="#bei-verdachtigen-sitzungen" aria-label="Permalink to &quot;Bei verdächtigen Sitzungen&quot;">​</a></h2><ol><li>Widerrufe die Sitzung des Geräts.</li><li>Ändere Administratorpasswort und zugehörige Tokens.</li><li>Prüfe Zugangsdaten für Cloudflare, GitHub und Speicherkanäle.</li><li>Erstelle API Tokens bei Bedarf neu.</li></ol><h2 id="betriebshinweise" tabindex="-1">Betriebshinweise <a class="header-anchor" href="#betriebshinweise" aria-label="Permalink to &quot;Betriebshinweise&quot;">​</a></h2><ul><li>Auf gemeinsam genutzten Rechnern keine Sitzung offen lassen.</li><li>Nur wenige Konten mit Administratorrechten behalten.</li><li>Angemeldete Geräte regelmäßig prüfen.</li><li>Alte oder unbekannte Sitzungen entfernen.</li></ul>',19)])])}const p=r(u,[["render",o]]);export{b as __pageData,p as default};
